import React from 'react';
import { Redirect, Route, Switch } from "react-router-dom";
import { HomePage } from './components/HomePage';
import { ArticlesPage } from './components/ArticlesPage';
import './Main.scss';

export const Main = () => {
  // const match = useRouteMatch();
  // console.log(match);

  return (
    <div className="Main">
      <Switch>
        <Route path="/home">
          <HomePage />
        </Route>
        <Route path="/articles">
          <ArticlesPage />
        </Route>
        <Redirect to="/home" />
      </Switch>
    </div>
  );
};
